import { useState } from "react";
import { recipes } from "../../data/index";

const NAV = [
  { icon: "📊", label: "Dashboard", id: "overview" },
  { icon: "🍴", label: "My Creations", id: "creations", active: true },
  { icon: "📈", label: "Analytics", id: "analytics" },
  { icon: "👥", label: "Followers", id: "followers" },
  { icon: "💬", label: "Reviews", id: "reviews" },
];

const TABS = ["All Recipes", "Live", "Pending Review", "Rejected"];

const STATUS_COLORS = {
  Live: { bg: "rgba(58,171,94,.12)", color: "#2d8a4e" },
  "Pending Review": { bg: "rgba(232,180,47,.12)", color: "#a07800" },
  Rejected: { bg: "rgba(232,93,47,.12)", color: "#c0392b" },
};

export default function ChefDashboardPage({ setPage, setSelectedRecipe }) {
  const [activeNav, setActiveNav] = useState("creations");
  const [activeTab, setActiveTab] = useState("All Recipes");

  const filtered = activeTab === "All Recipes" ? recipes : recipes.filter(r => r.status === activeTab);

  return (
    <div className="sidebar-layout">
      <aside className="sidebar">
        <div className="sidebar-brand">
          <div className="sidebar-brand-icon">🍽</div>
          <div>
            <div className="sidebar-brand-name sidebar-brand-name-dark">RecipeNest</div>
            <div className="sidebar-brand-sub">Chef Studio</div>
          </div>
        </div>

        <div className="sidebar-nav">
          {NAV.map(item => (
            <button key={item.id} className={`sidebar-item sidebar-item-light ${activeNav === item.id ? "active" : ""}`} onClick={() => setActiveNav(item.id)}>
              <span>{item.icon}</span>{item.label}
            </button>
          ))}
        </div>

        <div className="sidebar-bottom">
          <button className="sidebar-item sidebar-item-light">⚙ Settings</button>
          <div className="sidebar-profile">
            <div className="sidebar-avatar" style={{ width:34, height:34, fontSize:12 }}>CM</div>
            <div>
              <div className="sidebar-profile-name sidebar-profile-name-light">Chef Mario</div>
              <div className="sidebar-profile-role">Master Chef</div>
            </div>
          </div>
          <button className="logout-btn" onClick={() => setPage("login")}>↩ Logout</button>
        </div>
      </aside>

      <div className="page-content">
        <div className="page-header">
          <div>
            <h1 className="page-title page-title-dark">My Creations</h1>
            <p className="page-sub">Manage your portfolio and track how your recipes are performing.</p>
          </div>
          <button className="action-cta">+ Create New Recipe</button>
        </div>

        {/* Stats */}
        <div className="stats-row">
          <div className="stat-card"><div className="stat-icon" style={{background:"#eef4ff"}}>👥</div><div><div className="stat-val">12.5k</div><div className="stat-label">Total Followers</div></div></div>
          <div className="stat-card"><div className="stat-icon" style={{background:"#fff0f0"}}>❤</div><div><div className="stat-val">45.8k</div><div className="stat-label">Recipe Likes</div></div></div>
          <div className="stat-card"><div className="stat-icon" style={{background:"#fffbea"}}>⭐</div><div><div className="stat-val">4.8</div><div className="stat-label">Average Rating</div></div></div>
        </div>

        {/* Tabs */}
        <div className="tab-bar">
          {TABS.map(tab => (
            <button key={tab} className={`tab-btn ${activeTab === tab ? "active" : ""}`} onClick={() => setActiveTab(tab)}>{tab}</button>
          ))}
        </div>

        {/* Recipe Grid */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:20 }}>
          {filtered.map(recipe => (
            <div key={recipe.id} style={{ background:"#fff", borderRadius:12, overflow:"hidden", border:"1px solid #eee", cursor:"pointer", transition:"box-shadow .2s" }}
              onClick={() => { setSelectedRecipe(recipe); setPage("recipe-detail"); }}
              onMouseEnter={e => e.currentTarget.style.boxShadow="0 6px 24px rgba(0,0,0,.1)"}
              onMouseLeave={e => e.currentTarget.style.boxShadow="none"}>
              <div style={{ position:"relative" }}>
                <img src={recipe.image} alt={recipe.title} style={{ width:"100%", height:150, objectFit:"cover", display:"block" }} />
                <span style={{ position:"absolute", top:10, left:10, ...STATUS_COLORS[recipe.status], fontSize:10, fontWeight:700, padding:"3px 8px", borderRadius:99, letterSpacing:".5px", textTransform:"uppercase" }}>
                  ● {recipe.status}
                </span>
              </div>
              <div style={{ padding:14 }}>
                <div style={{ fontSize:14, fontWeight:600, color:"#1a1a1a", marginBottom:4 }}>{recipe.title}</div>
                <div style={{ fontSize:11, color:"#bbb" }}>Updated {recipe.updatedAgo}</div>
              </div>
              <div style={{ display:"flex", gap:8, padding:"10px 14px", borderTop:"1px solid #f5f4f0" }} onClick={e => e.stopPropagation()}>
                {[["✏","edit"],["📊","stats"],["🗑","del"]].map(([icon, type]) => (
                  <button key={type} style={{ background:"#f5f4f0", border:"none", padding:"7px 10px", borderRadius:7, fontSize:13, transition:"background .15s" }}
                    onMouseEnter={e => e.currentTarget.style.background = type === "del" ? "#ffeeed" : "#ede9e0"}
                    onMouseLeave={e => e.currentTarget.style.background = "#f5f4f0"}>
                    {icon}
                  </button>
                ))}
              </div>
            </div>
          ))}

          {/* New draft */}
          <div style={{ background:"#fff", border:"2px dashed #ddd", borderRadius:12, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", minHeight:220, gap:10, padding:20, cursor:"default" }}>
            <div style={{ width:48, height:48, background:"#f5f4f0", borderRadius:12, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22 }}>📝</div>
            <div style={{ fontSize:13, fontWeight:600, color:"#555" }}>New Idea?</div>
            <div style={{ fontSize:12, color:"#bbb", textAlign:"center", maxWidth:160 }}>Start drafting your next culinary masterpiece.</div>
            <button style={{ background:"#f5f4f0", border:"none", padding:"8px 18px", borderRadius:8, fontSize:12, fontWeight:600, color:"#555" }}>New Draft</button>
          </div>
        </div>
      </div>
    </div>
  );
}
